SELECT * FROM inpatient_order
WHERE deleted = 0

    AND (patient_name LIKE CONCAT('%', #{keyword}, '%') OR inpatient_no LIKE CONCAT('%', #{keyword}, '%') OR order_no LIKE CONCAT('%', #{keyword}, '%'))


    AND inpatient_id = #{inpatientId}


    AND status = #{status}

ORDER BY order_time DESC
